-- =====================================================================
-- Restaurantes Secretos — conteúdo PAGO movido para o servidor.
-- Antes ficava embutido em js/app.js (qualquer um lia no DevTools).
-- Agora vive aqui, protegido por RLS: a anon key NAO le esta tabela.
-- Só o endpoint /api/restaurantes-secretos (que usa a SERVICE KEY e
-- valida a compra) consegue devolver esse conteúdo.
--
-- Como aplicar: Supabase → SQL Editor → cole tudo → Run.
-- =====================================================================

create table if not exists public.restaurantes_secretos (
  id        bigint generated always as identity primary key,
  ordem     int  not null,
  cat       text not null,
  cat_icon  text,
  emoji     text,
  nome      text not null,
  selo      text,
  faixa     text,
  preco     text,
  descricao text,
  publico   text,
  dica      text
);

-- Liga o RLS e NAO cria policy de leitura publica.
-- Resultado: nem a anon key nem usuarios logados leem direto.
-- A service_role (usada no backend) ignora o RLS por padrao.
alter table public.restaurantes_secretos enable row level security;

-- Limpa antes de popular (idempotente — pode rodar de novo sem duplicar).
truncate public.restaurantes_secretos restart identity;

